    $content: string.slice($value, 5, string.length($value) - 1); // Remove var( and )
    @if string.index($content, ",") {
      $parts: str-split($content, ",");
      $var-name: string.slice(nth($parts, 1), 1);
      $fallback: string.slice(nth($parts, 2), 2); // Remove leading space
