    $parsed: parse-env($parsed);
    @return $parsed;
  }

  // Handle underscore replacement for spaces in complex values
  @if string.index($value, "_") {
    $value: str-replace($value, "_", " ");
  }

  // Original parsing logic
  @if string.index($value, "px") or string.index($value, "rem") or string.index($value, "em") or 
      string.index($value, "%") or string.index($value, "vh") or string.index($value, "vw") or
      string.index($value, "ch") or string.index($value, "ex") or string.index($value, "vmin") or
      string.index($value, "vmax") or string.index($value, "dvh") or string.index($value, "dvw") {
